const S={fondo:{minHeight:"100vh",background:C.fondo,fontFamily:FC,color:C.texto},pantalla:{minHeight:"100vh",background:C.fondo,display:"flex",justifyContent:"center",alignItems:"center",fontFamily:FC},header:{background:C.panel,padding:"0 24px",height:56,display:"flex",justifyContent:"space-between",alignItems:"center",borderBottom:`2px solid ${C.azul}`,position:"sticky",top:0,zIndex:100},logo:{color:C.azulC,fontSize:18,fontWeight:"bold",fontFamily:FT},cont:{maxWidth:980,margin:"0 auto",padding:"24px 16px"},card:{background:C.tarjeta,padding:"32px 28px",borderRadius:16,width:"100%",maxWidth:500,display:"flex",flexDirection:"column",gap:14,boxShadow:"0 12px 40px rgba(0,0,0,0.6)",border:`1px solid ${C.borde}`},titulo:{color:C.azulC,fontSize:22,fontWeight:"bold",margin:0,textAlign:"center",fontFamily:FT},sub:{color:C.textoS,textAlign:"center",margin:"0 0 8px",fontSize:13},lbl:{color:C.textoS,fontSize:12,marginBottom:4,fontWeight:"500"},inp:{padding:"10px 13px",borderRadius:8,border:`1px solid ${C.borde}`,background:"#0a1128",color:C.texto,fontSize:13,width:"100%",boxSizing:"border-box",fontFamily:FC,outline:"none"},ta:{padding:"10px 13px",borderRadius:8,border:`1px solid ${C.borde}`,background:"#0a1128",color:C.texto,fontSize:13,width:"100%",boxSizing:"border-box",fontFamily:FC,outline:"none",resize:"vertical",minHeight:80},sel:{padding:"10px 13px",borderRadius:8,border:`1px solid ${C.borde}`,background:"#0a1128",color:C.texto,fontSize:13,flex:1,fontFamily:FC,outline:"none"},btnA:{padding:"11px 18px",borderRadius:8,border:"none",background:`linear-gradient(135deg,${C.azul},#1d4ed8)`,color:"#fff",fontWeight:"700",fontSize:13,cursor:"pointer",width:"100%",fontFamily:FT},btnG:{padding:"10px 18px",borderRadius:8,border:`1px solid ${C.borde}`,background:"transparent",color:C.textoS,fontSize:13,cursor:"pointer",width:"100%",fontFamily:FC},btnV:{padding:"11px 18px",borderRadius:8,border:"none",background:`linear-gradient(135deg,${C.verde},#047857)`,color:"#fff",fontWeight:"700",fontSize:13,cursor:"pointer",width:"100%",fontFamily:FT},btnN:{padding:"11px 18px",borderRadius:8,border:"none",background:`linear-gradient(135deg,${C.naranja},#b45309)`,color:"#fff",fontWeight:"700",fontSize:13,cursor:"pointer",fontFamily:FT},btnM:{padding:"11px 18px",borderRadius:8,border:"none",background:`linear-gradient(135deg,${C.morado},#5b21b6)`,color:"#fff",fontWeight:"700",fontSize:13,cursor:"pointer",width:"100%",fontFamily:FT},btnSm:{padding:"5px 11px",borderRadius:6,border:`1px solid ${C.borde}`,background:"transparent",color:C.textoS,cursor:"pointer",fontSize:11},fila:{display:"flex",gap:10},bloque:{background:C.tarjeta,padding:20,borderRadius:12,marginBottom:14,border:`1px solid ${C.borde}`},tBloque:{color:C.azulC,fontSize:17,marginBottom:8,marginTop:0,fontFamily:FT,fontWeight:"bold"},grid2:{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8},grid3:{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8},opcion:(sel)=>({padding:10,borderRadius:8,border:sel?`2px solid ${C.azulC}`:`1px solid ${C.borde}`,background:sel?"#0f2a47":"#0a1128",cursor:"pointer",transition:"all 0.15s"}),oLbl:{color:C.texto,fontWeight:"700",fontSize:12,margin:0},oDesc:{color:C.textoS,fontSize:11,margin:"2px 0 0"},sep:{borderTop:`1px solid ${C.borde}`,margin:"14px 0"},chip:{display:"inline-block",background:"#0f2a47",border:`1px solid ${C.azul}`,color:C.azulC,padding:"2px 9px",borderRadius:20,fontSize:11,margin:2},err:{color:C.err,textAlign:"center",margin:0,fontSize:12},ok_msg:{color:C.ok,textAlign:"center",margin:0,fontSize:12},badge:(col)=>({background:col,color:"#fff",fontSize:10,fontWeight:"bold",padding:"2px 6px",borderRadius:20}),overlay:{position:"fixed",inset:0,background:"rgba(0,0,0,0.8)",zIndex:200,display:"flex",alignItems:"center",justifyContent:"center",padding:16},modal:{background:C.tarjeta,borderRadius:14,border:`1px solid ${C.borde}`,width:"100%",maxWidth:620,maxHeight:"90vh",display:"flex",flexDirection:"column",overflow:"hidden"},mHead:{padding:"18px 22px 14px",borderBottom:`1px solid ${C.borde}`,display:"flex",justifyContent:"space-between",alignItems:"center"},mBody:{padding:"18px 22px",overflowY:"auto",flex:1},mFoot:{padding:"14px 22px",borderTop:`1px solid ${C.borde}`,display:"flex",gap:8},pre:{whiteSpace:"pre-wrap",color:"#CBD5E1",fontSize:12,lineHeight:1.9,margin:0,fontFamily:"'Courier New',monospace"},pasoBola:(a,c2)=>({width:28,height:28,borderRadius:"50%",display:"flex",alignItems:"center",justifyContent:"center",fontSize:11,fontWeight:"bold",background:c2?C.verde:a?C.azul:"#111827",color:(c2||a)?"white":"#4a5a70",border:a?`2px solid ${C.azulC}`:c2?`2px solid ${C.verde}`:`1px solid ${C.borde}`})};
